/**
	 * Migrate state codes in the tax rates table.
	 *
	 * @since 7.0.0
	 *
	 * @param string $country_code The country that has the states for which the migration is needed.
	 * @param array  $old_to_new_states_mapping An associative array where keys are the old state codes and values are the new state codes.
	 * @return void
	 */
function migrate_country_states_for_tax_rates( string $country_code, array $old_to_new_states_mapping ): void {
		global $wpdb;

		if ( empty( $old_to_new_states_mapping ) ) {
			return;
		}

		// Build a single CASE WHEN UPDATE for all state code migrations.
		$case_sql = '';
		$args     = array();

		foreach ( $old_to_new_states_mapping as $old_state_code => $new_state_code ) {
			$case_sql .= $wpdb->prepare( 'WHEN tax_rate_state = %s THEN %s ', $old_state_code, $new_state_code );
			$args[]    = $old_state_code;
		}

		$old_codes_placeholders = implode( ', ', array_fill( 0, count( $args ), '%s' ) );

		// phpcs:ignore WordPress.DB.DirectDatabaseQuery, WordPress.DB.PreparedSQL.InterpolatedNotPrepared
		$wpdb->query(
			$wpdb->prepare(
				"UPDATE {$wpdb->prefix}woocommerce_tax_rates
				SET tax_rate_state = CASE {$case_sql} ELSE tax_rate_state END
				WHERE tax_rate_country = %s
					AND tax_rate_state IN ( {$old_codes_placeholders} )", // phpcs:ignore WordPress.DB.PreparedSQL.InterpolatedNotPrepared
