/**
	 * Save the order of posts from sortable feature
	 *
	 * @return void
	 * @since 1.0
	 * @author Antonino Scarfi' <antonino.scarfi@yithemes.com>
	 */
function sort_posts() {
		check_ajax_referer( 'yith_woocommerce_ajax_search', 'nonce' );

		global $wpdb;

		if ( empty( $_REQUEST['order'] ) ) {
			wp_die();
		}

		parse_str( sanitize_text_field( wp_unslash( $_REQUEST['order'] ) ), $data );

		if ( ! is_array( $data ) ) {
			wp_die();
		}

		// Flatten the nested data structure to a list of post IDs in order.
		$id_arr = array();
		foreach ( $data as $key => $values ) {
			foreach ( (array) $values as $position => $id ) {
				$id_arr[] = (int) $id;
			}
		}

		if ( empty( $id_arr ) ) {
			wp_die();
		}

		$placeholders = implode( ', ', array_fill( 0, count( $id_arr ), '%d' ) );

		// Fetch all current menu_order values in a single query.
		// phpcs:ignore WordPress.DB.DirectDatabaseQuery, WordPress.DB.PreparedSQL.InterpolatedNotPrepared
		$rows = $wpdb->get_results(
			$wpdb->prepare(
				"SELECT ID, menu_order FROM {$wpdb->posts} WHERE ID IN ( {$placeholders} )", // phpcs:ignore WordPress.DB.PreparedSQL.InterpolatedNotPrepared
				...$id_arr
			)
		);

		$menu_order_map = array();
		foreach ( $rows as $row ) {
			$menu_order_map[ (int) $row->ID ] = (int) $row->menu_order;
		}

		$menu_order_arr = array_values( $menu_order_map );
		sort( $menu_order_arr );

		// Build a single CASE WHEN UPDATE.
		$case_sql    = '';
		$update_args = array();
		$i           = 0;
		foreach ( $data as $key => $values ) {
			foreach ( (array) $values as $position => $id ) {
				$id           = (int) $id;
				$new_order    = $menu_order_arr[ $i ] ?? $i;
				$case_sql    .= $wpdb->prepare( 'WHEN ID = %d THEN %d ', $id, $new_order );
				$update_args[] = $id;
				$i++;
			}
		}

		if ( $case_sql && ! empty( $update_args ) ) {
			$ids_placeholders = implode( ', ', array_fill( 0, count( $update_args ), '%d' ) );
			// phpcs:ignore WordPress.DB.DirectDatabaseQuery, WordPress.DB.PreparedSQL.InterpolatedNotPrepared
			$wpdb->query(
				$wpdb->prepare(
					"UPDATE {$wpdb->posts} SET menu_order = CASE {$case_sql} ELSE menu_order END WHERE ID IN ( {$ids_placeholders} )", // phpcs:ignore WordPress.DB.PreparedSQL.InterpolatedNotPrepared
					array_merge( $update_args, $update_args )
				)
			);
		}

		wp_die();
	}

